// Extract PR/issue from GitHub webhook and build gateway payload with HMAC
const crypto = require('crypto');
const input = $input.item.json;
const body = input.body || input;

const action = body.action || '';
const repo = body.repository ? (body.repository.full_name || body.repository.name) : 'unknown';
let title = `GitHub ${body.pull_request ? 'PR' : 'Issue'}`;
let description = '';

if (body.pull_request) {
  const pr = body.pull_request;
  title = `[PR] ${pr.title || 'Untitled'} (#${pr.number})`;
  description = [
    `Repo: ${repo}`,
    `Action: ${action}`,
    `State: ${pr.state}`,
    (pr.body || '').slice(0, 1500)
  ].join('\n');
} else if (body.issue) {
  const iss = body.issue;
  title = `[Issue] ${iss.title || 'Untitled'} (#${iss.number})`;
  description = [
    `Repo: ${repo}`,
    `Action: ${action}`,
    `State: ${iss.state}`,
    (iss.body || '').slice(0, 1500)
  ].join('\n');
} else {
  title = `GitHub: ${repo} - ${body.action || 'event'}`;
  description = JSON.stringify(body).slice(0, 2000);
}

const payload = {
  title: String(title),
  description: String(description),
  priority: 'high',
  task_type: 'github'
};

const bodyStr = JSON.stringify(payload);
const secret = $env.WEBHOOK_SECRET || '';
const sig = secret ? crypto.createHmac('sha256', secret).update(bodyStr).digest('hex') : '';

return [{ json: { _rawBody: bodyStr, _signature: sig } }];
